UPDATE J09A_temp
SET ENTSCHEIDUNG = 'KSA'
WHERE HAUS IN (
  SELECT HAUS FROM (
    SELECT HAUS, COUNT(DISTINCT EQUNR) AS eq_count
    FROM J09A_temp
    GROUP BY HAUS
  )
  WHERE eq_count < 3
);

UPDATE J09A_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HAUS IN (
  SELECT HAUS FROM (
    SELECT HAUS, COUNT(DISTINCT EQUNR) AS eq_count
    FROM J09A_temp
    GROUP BY HAUS
  )
  WHERE eq_count >= 3
);

UPDATE J09A_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 = 0;

UPDATE J09A_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 BETWEEN 500 AND 599;
